import { addons } from '@storybook/preview-api';
/**
 * Synchronisation manuelle du thème (cf. preview.ts du Storybook React).
 * `withThemeByDataAttribute` ne pose pas l'attribut sur `<html>` du
 * preview iframe dans cette version - on remplace par un decorator manuel
 * + écoute du channel global pour couvrir les pages MDX.
 */
if (typeof document !== 'undefined') {
    document.documentElement.setAttribute('data-theme', 'light');
    try {
        const channel = addons.getChannel();
        channel.on('globalsUpdated', (event) => {
            const theme = event?.globals?.['theme'];
            if (typeof theme === 'string') {
                document.documentElement.setAttribute('data-theme', theme);
            }
        });
    }
    catch {
        // Si l'API channel n'est pas disponible, le decorator ci-dessous prend le relais.
    }
}
const preview = {
    globalTypes: {
        theme: {
            name: 'Theme',
            description: 'Thème de la palette pf-ds',
            defaultValue: 'light',
            toolbar: {
                icon: 'paintbrush',
                items: [
                    { value: 'light', title: 'Clair', icon: 'sun' },
                    { value: 'dark', title: 'Sombre', icon: 'moon' },
                ],
                showName: true,
                dynamicTitle: true,
            },
        },
    },
    parameters: {
        controls: {
            matchers: {
                color: /(background|color)$/i,
                date: /Date$/i,
            },
        },
        backgrounds: { disable: true },
        layout: 'centered',
        options: {
            // Ordre de la sidebar : doit être inline (Storybook 8 ne suit pas les imports
            // dans cette config). Si on modifie, penser à synchroniser le preview React.
            storySort: {
                order: [
                    'Documentation générale',
                    [
                        'Introduction',
                        'Décisions de design',
                        'Iconographie',
                        'Tokens',
                        ['Palette', 'Sémantique', 'Typographie', 'Spacing', 'Radii', 'Shadows'],
                        'Composants graphiques',
                        ['Button', 'Input', 'Textarea', 'Select', 'Checkbox', 'Radio', 'Switch', 'DatePicker', 'FileUpload', 'Tabs', 'Accordion', 'Breadcrumb', 'Pagination', 'Steps', 'Tag', 'Avatar', 'Tooltip', 'Link', 'Highlight', 'Progress', 'Skeleton', 'Toast', 'Notification', 'Table', 'Logo', 'Header', 'Footer', 'MainNavigation', 'SideMenu', 'LanguageSwitcher', 'Card', 'Alert', 'Dialog'],
                        'Différences React ↔ Angular',
                        'Décisions à prendre',
                    ],
                    'Angular',
                    ['Installation', 'Patterns'],
                    'Composants graphiques',
                    ['Button', 'Input', 'Textarea', 'Select', 'Checkbox', 'Radio', 'Switch', 'DatePicker', 'FileUpload', 'Tabs', 'Accordion', 'Breadcrumb', 'Pagination', 'Steps', 'Tag', 'Avatar', 'Tooltip', 'Link', 'Highlight', 'Progress', 'Skeleton', 'Toast', 'Notification', 'Table', 'Logo', 'Header', 'Footer', 'MainNavigation', 'SideMenu', 'LanguageSwitcher', 'Card', 'Alert', 'Dialog'],
                    'Composants fonctionnels',
                    [
                        'Keycloak',
                        ['AuthLogin', 'AuthRegister', 'AuthResetPassword', 'AuthUpdatePassword', 'AuthOtp', 'AuthSessionExpired', 'AuthError'],
                    ],
                ],
            },
        },
    },
    decorators: [
        (storyFn, context) => {
            const theme = context.globals['theme'] ?? 'light';
            if (typeof document !== 'undefined') {
                document.documentElement.setAttribute('data-theme', theme);
            }
            return storyFn();
        },
    ],
};
export default preview;
